const input = $json.body ?? $json;
const notification = input.notification ?? {};
const metricsIn = input.metrics ?? {};
const incidents = Array.isArray(input.incidents) ? input.incidents : [];

const metrics = {
  contracts_evaluated: Number(metricsIn.contracts_evaluated ?? 0),
  ads_evaluated: Number(metricsIn.ads_evaluated ?? 0),
  paused_success_count: Number(metricsIn.paused_success_count ?? 0),
  paused_error_count: Number(metricsIn.paused_error_count ?? 0),
  expired_unpaused_count: Number(metricsIn.expired_unpaused_count ?? 0),
  preventive_48h_count: Number(metricsIn.preventive_48h_count ?? 0),
  duration_ms: Number(metricsIn.duration_ms ?? 0)
};

const executionStatus = String(input.execution_status ?? input.status ?? 'unknown').toLowerCase();
const isCritical = metrics.expired_unpaused_count > 0;

let severity = 'INFO';
if (isCritical) {
  severity = 'CRITICAL';
} else if (executionStatus !== 'success' || metrics.paused_error_count > 0 || incidents.length > 0) {
  severity = 'WARN';
}

const correlationId = String(input.correlation_id ?? input.execution_id ?? `ops-${Date.now()}`);
const timezone = input.timezone ?? 'America/Argentina/Buenos_Aires';

return [{
  json: {
    ...input,
    correlation_id: correlationId,
    execution_status: executionStatus,
    timezone,
    incidents,
    metrics,
    notification,
    derived: {
      severity,
      is_critical: isCritical,
      execution_mode: String(input.execution_mode ?? 'scheduled').toLowerCase(),
      executed_at: input.executed_at ?? new Date().toISOString()
    }
  }
}];

return [{
  json: {
    event: 'ops_notification_channel_error',
    channel: String($json.notification?.channel ?? 'unknown').toLowerCase(),
    severity: $json.derived?.severity ?? 'WARN',
    correlation_id: $json.correlation_id ?? null,
    execution_id: $json.execution_id ?? null,
    message: 'Fallo de env?o de notificaci?n. MVP sin fallback autom?tico entre canales.',
    timestamp: new Date().toISOString()
  }
}];

return [{
  json: {
    event: 'ops_notification_sent',
    channel: 'slack',
    severity: $json.derived?.severity ?? 'INFO',
    correlation_id: $json.correlation_id ?? null,
    execution_id: $json.execution_id ?? null,
    message: 'Notificaci?n enviada por Slack.',
    timestamp: new Date().toISOString()
  }
}];

return [{
  json: {
    event: 'ops_notification_sent',
    channel: 'telegram',
    severity: $json.derived?.severity ?? 'INFO',
    correlation_id: $json.correlation_id ?? null,
    execution_id: $json.execution_id ?? null,
    message: 'Notificaci?n enviada por Telegram.',
    timestamp: new Date().toISOString()
  }
}];

return [{
  json: {
    event: 'ops_notification_channel_unsupported',
    channel: String($json.notification?.channel ?? 'undefined').toLowerCase(),
    severity: 'ERROR',
    correlation_id: $json.correlation_id ?? null,
    execution_id: $json.execution_id ?? null,
    message: 'Canal no soportado. Solo Slack o Telegram en MVP.',
    timestamp: new Date().toISOString()
  }
}];

const input = $json ?? {};
const nowIso = new Date().toISOString();

const eventType = String(input.event_type ?? input.event ?? input.action ?? "ops_notification_event").trim() || "ops_notification_event";
const statusRaw = String(input.status ?? input.result ?? "").trim();

let resultValue = statusRaw ? statusRaw.toLowerCase() : "";
if (!resultValue) {
  if (eventType.includes("sent")) resultValue = "success";
  else if (eventType.includes("error") || eventType.includes("unsupported")) resultValue = "error";
  else resultValue = "unknown";
}

const executionId = String(
  input.execution_id
  ?? input.logical_execution_id
  ?? input.meta?.execution_id
  ?? input.execution?.id
  ?? $execution?.id
  ?? ""
);

const channelValue = String(
  input.channel
  ?? input.notification?.channel
  ?? ""
).trim().toLowerCase();

const severityValue = String(
  input.severity
  ?? input.derived?.severity
  ?? ""
).trim().toUpperCase();

return [{
  json: {
    execution_id: executionId,
    correlation_id: String(input.correlation_id ?? ""),
    action: eventType,
    event_type: eventType,
    status: resultValue,
    result: resultValue,
    channel: channelValue,
    severity: severityValue,
    timestamp: String(input.timestamp ?? nowIso),
    source_workflow: "ops-reporting-alerts"
  }
}];

const input = $json ?? {};
const nowIso = new Date().toISOString();
const severity = String(input.severity ?? input.derived?.severity ?? 'CRITICAL').trim().toUpperCase() || 'CRITICAL';
const eventType = String(input.event_type ?? input.event ?? input.action ?? 'ops_alert_critical').trim() || 'ops_alert_critical';
const correlationId = String(input.correlation_id ?? input.execution_id ?? input.logical_execution_id ?? '').trim();
const executionId = String(input.execution_id ?? input.logical_execution_id ?? input.meta?.execution_id ?? '').trim();
const contractId = String(input.Contrato_ID ?? input.contract_id ?? input.contractId ?? input.contracto_id ?? input.contract ?? '').trim();
const adId = String(input.Ad_ID ?? input.ad_id ?? input.adId ?? '').trim();
const motive = String(input.message_text ?? input.message ?? input.derived?.reason ?? input.derived?.alert_reason ?? '').trim() || 'CRITICAL: vencidos sin pausar';
const createdAt = String(input.timestamp ?? input.created_at ?? input.derived?.executed_at ?? nowIso);
const alertId = String(input.alert_id ?? input.Alerta_ID ?? `${correlationId || executionId || 'ops'}-${Date.now()}`);

return [{
  json: {
    Alerta_ID: alertId,
    Severidad: severity,
    Contrato_ID: contractId,
    Ad_ID: adId,
    Motivo: motive,
    Correlation_ID: correlationId,
    Creada_At: createdAt,
    Estado: 'Abierta',
    source_workflow: 'ops-reporting-alerts',
    event_type: eventType,
    execution_id: executionId
  }
}];

